import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  Button,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import { authorize, refresh, revoke } from 'react-native-app-auth';
import * as Keychain from 'react-native-keychain';
import CryptoJS from 'crypto-js';

const config = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your-mobile-client-id',
  redirectUrl: 'com.yourapp://oauth/callback',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  usePKCE: true,
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-oauth-server.com/oauth/authorize',
    tokenEndpoint: 'https://your-oauth-server.com/oauth/token',
    revocationEndpoint: 'https://your-oauth-server.com/oauth/revoke',
  },
};

const KEYCHAIN_SERVICE = 'com.yourapp.oauth';
const TOKEN_REFRESH_THRESHOLD = 300;

const secureStorage = {
  async saveTokens(tokens) {
    try {
      const encryptedData = JSON.stringify({
        accessToken: tokens.accessToken,
        refreshToken: tokens.refreshToken,
        accessTokenExpirationDate: tokens.accessTokenExpirationDate,
        idToken: tokens.idToken,
      });
      
      await Keychain.setGenericPassword(
        'oauth_tokens',
        encryptedData,
        {
          service: KEYCHAIN_SERVICE,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
          securityLevel: Keychain.SECURITY_LEVEL.SECURE_HARDWARE,
        }
      );
      return true;
    } catch (error) {
      console.error('Failed to save tokens:', error);
      return false;
    }
  },

  async getTokens() {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: KEYCHAIN_SERVICE,
      });
      
      if (credentials) {
        return JSON.parse(credentials.password);
      }
      return null;
    } catch (error) {
      console.error('Failed to retrieve tokens:', error);
      return null;
    }
  },

  async clearTokens() {
    try {
      await Keychain.resetGenericPassword({
        service: KEYCHAIN_SERVICE,
      });
      return true;
    } catch (error) {
      console.error('Failed to clear tokens:', error);
      return false;
    }
  },
};

const tokenManager = {
  async isTokenExpired(expirationDate) {
    if (!expirationDate) return true;
    const expiryTime = new Date(expirationDate).getTime();
    const currentTime = Date.now();
    const timeUntilExpiry = (expiryTime - currentTime) / 1000;
    return timeUntilExpiry <= TOKEN_REFRESH_THRESHOLD;
  },

  async refreshAccessToken(refreshToken) {
    try {
      const refreshedState = await refresh(config, {
        refreshToken: refreshToken,
      });
      
      await secureStorage.saveTokens(refreshedState);
      return refreshedState;
    } catch (error) {
      console.error('Token refresh failed:', error);
      throw error;
    }
  },

  async getValidAccessToken() {
    try {
      const tokens = await secureStorage.getTokens();
      
      if (!tokens) {
        throw new Error('No tokens available');
      }

      const isExpired = await this.isTokenExpired(
        tokens.accessTokenExpirationDate
      );

      if (isExpired && tokens.refreshToken) {
        const refreshedTokens = await this.refreshAccessToken(
          tokens.refreshToken
        );
        return refreshedTokens.accessToken;
      }

      return tokens.accessToken;
    } catch (error) {
      console.error('Failed to get valid access token:', error);
      throw error;
    }
  },
};

const apiClient = {
  async makeAuthenticatedRequest(url, options = {}) {
    try {
      const accessToken = await tokenManager.getValidAccessToken();
      
      const response = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          'Authorization': `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
        },
      });

      if (response.status === 401) {
        throw new Error('Unauthorized - token may be invalid');
      }

      return response;
    } catch (error) {
      console.error('API request failed:', error);
      throw error;
    }
  },
};

export default function App() {
  const [authState, setAuthState] = useState(null);
  const [loading, setLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);

  useEffect(() => {
    checkAuthStatus();
  }, []);

  const checkAuthStatus = async () => {
    try {
      const tokens = await secureStorage.getTokens();
      if (tokens) {
        setAuthState(tokens);
        await fetchUserInfo();
      }
    } catch (error) {
      console.error('Auth check failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogin = async () => {
    try {
      setLoading(true);
      const result = await authorize(config);
      
      await secureStorage.saveTokens(result);
      setAuthState(result);
      
      await fetchUserInfo();
      
      Alert.alert('Success', 'Successfully authenticated!');
    } catch (error) {
      console.error('Login failed:', error);
      Alert.alert(
        'Authentication Failed',
        error.message || 'An error occurred during login'
      );
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      setLoading(true);
      
      if (authState?.accessToken) {
        try {
          await revoke(config, {
            tokenToRevoke: authState.accessToken,
            includeBasicAuth: false,
          });
        } catch (revokeError) {
          console.error('Token revocation failed:', revokeError);
        }
      }
      
      await secureStorage.clearTokens();
      setAuthState(null);
      setUserInfo(null);
      
      Alert.alert('Success', 'Successfully logged out');
    } catch (error) {
      console.error('Logout failed:', error);
      Alert.alert('Logout Failed', 'An error occurred during logout');
    } finally {
      setLoading(false);
    }
  };

  const fetchUserInfo = async () => {
    try {
      const response = await apiClient.makeAuthenticatedRequest(
        'https://your-oauth-server.com/api/userinfo'
      );
      
      if (response.ok) {
        const data = await response.json();
        setUserInfo(data);
      }
    } catch (error) {
      console.error('Failed to fetch user info:', error);
    }
  };

  const handleRefreshToken = async () => {
    try {
      setLoading(true);
      
      if (!authState?.refreshToken) {
        Alert.alert('Error', 'No refresh token available');
        return;
      }

      const refreshedState = await tokenManager.refreshAccessToken(
        authState.refreshToken
      );
      
      setAuthState(refreshedState);
      Alert.alert('Success', 'Token refreshed successfully');
    } catch (error) {
      console.error('Token refresh failed:', error);
      Alert.alert('Refresh Failed', 'Failed to refresh token');
      await handleLogout();
    } finally {
      setLoading(false);
    }
  };

  const makeProtectedApiCall = async () => {
    try {
      setLoading(true);
      const response = await apiClient.makeAuthenticatedRequest(
        'https://your-oauth-server.com/api/protected-resource'
      );
      
      if (response.ok) {
        const data = await response.json();
        Alert.alert('Success', JSON.stringify(data, null, 2));
      } else {
        Alert.alert('Error', `API call failed: ${response.status}`);
      }
    } catch (error) {
      console.error('API call failed:', error);
      Alert.alert('Error', 'Failed to make API call');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>OAuth 2.0 Authentication</Text>
      
      {authState ? (
        <View style={styles.authenticatedContainer}>
          <Text style={styles.statusText}>✓ Authenticated</Text>
          
          {userInfo && (
            <View style={styles.userInfoContainer}>
              <Text style={styles.userInfoTitle}>User Information:</Text>
              <Text style={styles.userInfoText}>
                {JSON.stringify(userInfo, null, 2)}
              </Text>
            </View>
          )}
          
          <View style={styles.buttonContainer}>
            <Button
              title="Refresh Token"
              onPress={handleRefreshToken}
              disabled={loading}
            />
            <View style={styles.buttonSpacer} />
            <Button
              title="Make API Call"
              onPress={makeProtectedApiCall}
              disabled={loading}
            />
            <View style={styles.buttonSpacer} />
            <Button
              title="Logout"
              onPress={handleLogout}
              color="#ff0000"
              disabled={loading}
            />
          </View>
        </View>
      ) : (
        <View style={styles.unauthenticatedContainer}>
          <Text style={styles.statusText}>Not authenticated</Text>
          <Button
            title="Login with OAuth"
            onPress={handleLogin}
            disabled={loading}
          />
        </View>
      )}
    </View>
  );
}

